proof_block:
// The ensures of `det_init2none` is an implication
//     (LHS-conjunction-of-foralls-and-wfs) ==> det_init2none_equal(...).
// The previous attempt's bare `assert(forall ... .is_None())` failed
// because that `forall` is the *antecedent* of the implication, not a
// free hypothesis at the prelude point.
//
// We introduce the LHS via a ghost `if` whose condition is exactly that
// LHS conjunction; inside the `if` branch each conjunct (including the
// two None-foralls) becomes a hypothesis, so we can instantiate their
// otherwise-disjoint triggers `post1_self_@[index]` /
// `post2_self_@[index]` at the same `i` and close with Seq extensional
// equality.
if ((forall|index: int| 0 <= index < N ==> #[trigger] post1_self_@[index].is_None())
    && post1_self_.wf()
    && (forall|index: int| 0 <= index < N ==> #[trigger] post2_self_@[index].is_None())
    && post2_self_.wf())
{
    // Pointwise: at every in-range i, both views carry `None`, hence equal.
    // The two explicit indexings below fire the two foralls' triggers
    // (`post1_self_@[i]` and `post2_self_@[i]`) at the same `i`.
    assert forall|i: int| 0 <= i < N implies post1_self_@[i] == post2_self_@[i] by {
        assert(post1_self_@[i].is_None());
        assert(post2_self_@[i].is_None());
        // Both elements are `None`, so they are equal as `Option<T>` values.
    }

    // Both views have length N from `wf()`; matching lengths + pointwise
    // equality is exactly Seq extensional equality (`=~=`), which Verus
    // upgrades to plain `==` on Seq.
    assert(post1_self_@.len() == N);
    assert(post2_self_@.len() == N);
    assert(post1_self_@ =~= post2_self_@);
    assert(post1_self_@ == post2_self_@);

    // `view` is `#[verifier(inline)]` and returns `self.seq@`, so view
    // equality is definitionally seq-field equality.
    assert(post1_self_.seq@ == post2_self_.seq@);

    // `Ghost<X>` equality reduces to equality of the inner spec value,
    // so the two `seq: Ghost<Seq<Option<T>>>` fields are equal.
    assert(post1_self_.seq == post2_self_.seq);
}
